package org.example.mazadat.Service;

import com.itextpdf.io.font.PdfEncodings;
import com.itextpdf.kernel.font.PdfFont;
import com.itextpdf.kernel.font.PdfFontFactory;
import com.itextpdf.io.image.ImageData;
import com.itextpdf.io.image.ImageDataFactory;
import com.itextpdf.kernel.pdf.PdfDocument;
import com.itextpdf.kernel.pdf.PdfWriter;
import com.itextpdf.layout.Document;
import com.itextpdf.layout.element.Image;
import com.itextpdf.layout.element.Paragraph;
import com.itextpdf.layout.element.Table;
import com.itextpdf.layout.properties.TextAlignment;
import lombok.RequiredArgsConstructor;
import org.example.mazadat.Api.ApiException;
import org.example.mazadat.Model.Auction;
import org.example.mazadat.Model.Buyer;
import org.example.mazadat.Repository.AuctionRepository;
import org.example.mazadat.Repository.BuyerRepository;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.nio.charset.StandardCharsets;

@Service
@RequiredArgsConstructor
public class ReceiptService {

    private final AuctionRepository auctionRepository;
    private final BuyerRepository buyerRepository;

    public byte[] generateReceiptPDF(Integer auctionId, Integer buyerId) {
        // Fetch auction
        Auction auction = auctionRepository.findById(auctionId).orElse(null);
        if (auction == null) {
            throw new ApiException("Auction not found");
        }

        // Verify auction has ended
        LocalDateTime now = LocalDateTime.now();
        if (auction.getEndDate() != null && now.isBefore(auction.getEndDate())) {
            throw new ApiException("Auction has not ended yet. Receipt can only be downloaded after the auction ends.");
        }

        // Fetch buyer
        Buyer buyer = buyerRepository.findById(buyerId).orElse(null);
        if (buyer == null) {
            throw new ApiException("Buyer not found");
        }

        // Verify buyer is the winner
        if (auction.getHighestBidder() == null || !auction.getHighestBidder().equals(buyer.getUser().getUsername())) {
            throw new ApiException("Only the auction winner can generate a receipt");
        }

        // Update auction status to ENDED if not already
        if (auction.getStatus() == null || !auction.getStatus().equals("ENDED")) {
            auction.setStatus("ENDED");
            auctionRepository.save(auction);
        }

        byte[] pdfBytes = createPDF(auction, buyer);
        if (pdfBytes == null || pdfBytes.length < 16) {
            throw new ApiException("Generated receipt is empty");
        }

        String pdfHeader = new String(pdfBytes, 0, 4, StandardCharsets.US_ASCII);
        if (!"%PDF".equals(pdfHeader)) {
            throw new ApiException("Generated receipt is invalid");
        }

        return pdfBytes;
    }

    private byte[] createPDF(Auction auction, Buyer buyer) {
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            PdfWriter writer = new PdfWriter(baos);
            PdfDocument pdfDoc = new PdfDocument(writer);
            Document doc = new Document(pdfDoc);
            PdfFont unicodeFont = loadUnicodeFont();
            doc.setFont(unicodeFont);

            // Add logo
            try {
                ClassPathResource resource = new ClassPathResource("static/logos/mazadat_green_logo.png");
                InputStream inputStream = resource.getInputStream();
                ImageData imageData = ImageDataFactory.create(inputStreamToByteArray(inputStream));
                Image logo = new Image(imageData).setWidth(100).setHeight(100);
                doc.add(logo);
            } catch (Exception e) {
                // Logo not found, continue without it
            }

            // Title
            Paragraph title = new Paragraph("MAZADAT AUCTION RECEIPT")
                    .setFontSize(24)
                    .setBold()
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginBottom(20);
            doc.add(title);

            // Receipt date
            String formattedDate = LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"));
            Paragraph dateP = new Paragraph("Receipt Generated: " + formattedDate)
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginBottom(20);
            doc.add(dateP);

            // Divider
            doc.add(new Paragraph("_".repeat(80)).setTextAlignment(TextAlignment.CENTER).setMarginBottom(20));

            // Auction Details
            Paragraph auctionTitle = new Paragraph("AUCTION DETAILS")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(auctionTitle);

            Table auctionTable = new Table(2).setWidth(500);
            auctionTable.addCell(new Paragraph("Auction ID:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(String.valueOf(auction.getId())).setFont(unicodeFont));
            auctionTable.addCell(new Paragraph("Auction Name:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(auction.getTitle() != null ? auction.getTitle() : "N/A").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph("Auction Description:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(auction.getDescription() != null ? auction.getDescription() : "N/A").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph("Selling Price:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(auction.getCurrentPrice() + " SR").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph("Auction End Date:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(auction.getEndDate() != null ?
                    auction.getEndDate().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss")) : "N/A").setFont(unicodeFont));
            doc.add(auctionTable);

            // Seller Details
            Paragraph sellerTitle = new Paragraph("SELLER INFORMATION")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(sellerTitle);

            Table sellerTable = new Table(2).setWidth(500);
            sellerTable.addCell(new Paragraph("Seller Name:").setFont(unicodeFont));
            sellerTable.addCell(new Paragraph(auction.getSeller().getUser().getUsername()).setFont(unicodeFont));
            sellerTable.addCell(new Paragraph("Seller Email:").setFont(unicodeFont));
            sellerTable.addCell(new Paragraph(auction.getSeller().getUser().getEmail()).setFont(unicodeFont));
            sellerTable.addCell(new Paragraph("Iban:").setFont(unicodeFont));
            sellerTable.addCell(new Paragraph(auction.getSeller().getIban() != null ?
                    auction.getSeller().getIban() : "Not provided").setFont(unicodeFont));
            doc.add(sellerTable);

            // Buyer Details
            Paragraph buyerTitle = new Paragraph("BUYER INFORMATION")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(buyerTitle);

            Table buyerTable = new Table(2).setWidth(500);
            buyerTable.addCell(new Paragraph("Buyer Name:").setFont(unicodeFont));
            buyerTable.addCell(new Paragraph(buyer.getUser().getUsername()).setFont(unicodeFont));
            buyerTable.addCell(new Paragraph("Buyer Email:").setFont(unicodeFont));
            buyerTable.addCell(new Paragraph(buyer.getUser().getEmail()).setFont(unicodeFont));
            buyerTable.addCell(new Paragraph("Phone:").setFont(unicodeFont));
            buyerTable.addCell(new Paragraph(buyer.getUser().getPhoneNumber() != null ?
                    buyer.getUser().getPhoneNumber() : "Not provided").setFont(unicodeFont));
            doc.add(buyerTable);

            // Footer
            doc.add(new Paragraph("_".repeat(80))
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginTop(20)
                    .setMarginBottom(10));
            Paragraph footer = new Paragraph("Thank you for using Mazadat! This is an official receipt.")
                    .setTextAlignment(TextAlignment.CENTER)
                    .setFontSize(10);
            doc.add(footer);

            // Close document - this will automatically close PdfDocument and Writer
            doc.close();

            return baos.toByteArray();
        } catch (Exception e) {
            throw new ApiException("Error generating PDF: " + e.getMessage());
        }
    }

    private PdfFont loadUnicodeFont() {
        try {
            // If you add a bundled font later, keep this first.
            ClassPathResource bundledFont = new ClassPathResource("static/fonts/NotoNaskhArabic-Regular.ttf");
            if (bundledFont.exists()) {
                return PdfFontFactory.createFont(
                        inputStreamToByteArray(bundledFont.getInputStream()),
                        PdfEncodings.IDENTITY_H,
                        PdfFontFactory.EmbeddingStrategy.PREFER_EMBEDDED
                );
            }
        } catch (Exception ignored) {
            // Fallbacks below
        }

        try {
            // Windows fallback for local development/runtime.
            return PdfFontFactory.createFont(
                    "C:/Windows/Fonts/arial.ttf",
                    PdfEncodings.IDENTITY_H,
                    PdfFontFactory.EmbeddingStrategy.PREFER_EMBEDDED
            );
        } catch (Exception ignored) {
            // Final fallback
        }

        try {
            return PdfFontFactory.createFont();
        } catch (Exception e) {
            throw new ApiException("Unable to load a PDF font: " + e.getMessage());
        }
    }

    private byte[] inputStreamToByteArray(InputStream is) throws Exception {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        int nRead;
        byte[] data = new byte[16384];
        while ((nRead = is.read(data, 0, data.length)) != -1) {
            buffer.write(data, 0, nRead);
        }
        return buffer.toByteArray();
    }
}

package org.example.mazadat.Service;

import com.itextpdf.io.font.PdfEncodings;
import com.itextpdf.kernel.font.PdfFont;
import com.itextpdf.kernel.font.PdfFontFactory;
import com.itextpdf.io.image.ImageData;
import com.itextpdf.io.image.ImageDataFactory;
import com.itextpdf.kernel.pdf.PdfDocument;
import com.itextpdf.kernel.pdf.PdfWriter;
import com.itextpdf.layout.Document;
import com.itextpdf.layout.element.Image;
import com.itextpdf.layout.element.Paragraph;
import com.itextpdf.layout.element.Table;
import com.itextpdf.layout.properties.BaseDirection;
import com.itextpdf.layout.properties.TextAlignment;
import lombok.RequiredArgsConstructor;
import org.example.mazadat.Api.ApiException;
import org.example.mazadat.Model.Auction;
import org.example.mazadat.Model.Buyer;
import org.example.mazadat.Repository.AuctionRepository;
import org.example.mazadat.Repository.BuyerRepository;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.nio.charset.StandardCharsets;

@Service
@RequiredArgsConstructor
public class ReceiptService {

    private final AuctionRepository auctionRepository;
    private final BuyerRepository buyerRepository;

    public byte[] generateReceiptPDF(Integer auctionId, Integer buyerId) {
        // Fetch auction
        Auction auction = auctionRepository.findById(auctionId).orElse(null);
        if (auction == null) {
            throw new ApiException("Auction not found");
        }

        // Verify auction has ended
        LocalDateTime now = LocalDateTime.now();
        if (auction.getEndDate() != null && now.isBefore(auction.getEndDate())) {
            throw new ApiException("Auction has not ended yet. Receipt can only be downloaded after the auction ends.");
        }

        // Fetch buyer
        Buyer buyer = buyerRepository.findById(buyerId).orElse(null);
        if (buyer == null) {
            throw new ApiException("Buyer not found");
        }

        // Verify buyer is the winner
        if (auction.getHighestBidder() == null || !auction.getHighestBidder().equals(buyer.getUser().getUsername())) {
            throw new ApiException("Only the auction winner can generate a receipt");
        }

        // Update auction status to ENDED if not already
        if (auction.getStatus() == null || !auction.getStatus().equals("ENDED")) {
            auction.setStatus("ENDED");
            auctionRepository.save(auction);
        }

        byte[] pdfBytes = createPDF(auction, buyer);
        if (pdfBytes == null || pdfBytes.length < 16) {
            throw new ApiException("Generated receipt is empty");
        }

        String pdfHeader = new String(pdfBytes, 0, 4, StandardCharsets.US_ASCII);
        if (!"%PDF".equals(pdfHeader)) {
            throw new ApiException("Generated receipt is invalid");
        }

        return pdfBytes;
    }

    private byte[] createPDF(Auction auction, Buyer buyer) {
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            PdfWriter writer = new PdfWriter(baos);
            PdfDocument pdfDoc = new PdfDocument(writer);
            Document doc = new Document(pdfDoc);
            PdfFont unicodeFont = loadUnicodeFont();
            doc.setFont(unicodeFont);

            // Add logo
            try {
                ClassPathResource resource = new ClassPathResource("static/logos/mazadat_green_logo.png");
                InputStream inputStream = resource.getInputStream();
                ImageData imageData = ImageDataFactory.create(inputStreamToByteArray(inputStream));
                Image logo = new Image(imageData).setWidth(100).setHeight(100);
                doc.add(logo);
            } catch (Exception e) {
                // Logo not found, continue without it
            }

            // Title
            Paragraph title = new Paragraph("MAZADAT AUCTION RECEIPT")
                    .setFontSize(24)
                    .setBold()
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginBottom(20);
            doc.add(title);

            // Receipt date
            String formattedDate = LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"));
            Paragraph dateP = new Paragraph("Receipt Generated: " + formattedDate)
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginBottom(20);
            doc.add(dateP);

            // Divider
            doc.add(new Paragraph("_".repeat(80)).setTextAlignment(TextAlignment.CENTER).setMarginBottom(20));

            // Auction Details
            Paragraph auctionTitle = new Paragraph("AUCTION DETAILS")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(auctionTitle);

            Table auctionTable = new Table(2).setWidth(500);
            auctionTable.addCell(labelCell("Auction ID:", unicodeFont));
            auctionTable.addCell(valueCell(String.valueOf(auction.getId()), unicodeFont));
            auctionTable.addCell(labelCell("Auction Name:", unicodeFont));
            auctionTable.addCell(valueCell(auction.getTitle() != null ? auction.getTitle() : "N/A", unicodeFont));
            auctionTable.addCell(labelCell("Auction Description:", unicodeFont));
            auctionTable.addCell(valueCell(auction.getDescription() != null ? auction.getDescription() : "N/A", unicodeFont));
            auctionTable.addCell(labelCell("Selling Price:", unicodeFont));
            auctionTable.addCell(valueCell(auction.getCurrentPrice() + " SR", unicodeFont));
            auctionTable.addCell(labelCell("Auction End Date:", unicodeFont));
            auctionTable.addCell(valueCell(auction.getEndDate() != null ?
                    auction.getEndDate().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss")) : "N/A", unicodeFont));
            doc.add(auctionTable);

            // Seller Details
            Paragraph sellerTitle = new Paragraph("SELLER INFORMATION")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(sellerTitle);

            Table sellerTable = new Table(2).setWidth(500);
            sellerTable.addCell(labelCell("Seller Name:", unicodeFont));
            sellerTable.addCell(valueCell(auction.getSeller().getUser().getUsername(), unicodeFont));
            sellerTable.addCell(labelCell("Seller Email:", unicodeFont));
            sellerTable.addCell(valueCell(auction.getSeller().getUser().getEmail(), unicodeFont));
            sellerTable.addCell(labelCell("Iban:", unicodeFont));
            sellerTable.addCell(valueCell(auction.getSeller().getIban() != null ?
                    auction.getSeller().getIban() : "Not provided", unicodeFont));
            doc.add(sellerTable);

            // Buyer Details
            Paragraph buyerTitle = new Paragraph("BUYER INFORMATION")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(buyerTitle);

            Table buyerTable = new Table(2).setWidth(500);
            buyerTable.addCell(labelCell("Buyer Name:", unicodeFont));
            buyerTable.addCell(valueCell(buyer.getUser().getUsername(), unicodeFont));
            buyerTable.addCell(labelCell("Buyer Email:", unicodeFont));
            buyerTable.addCell(valueCell(buyer.getUser().getEmail(), unicodeFont));
            buyerTable.addCell(labelCell("Phone:", unicodeFont));
            buyerTable.addCell(valueCell(buyer.getUser().getPhoneNumber() != null ?
                    buyer.getUser().getPhoneNumber() : "Not provided", unicodeFont));
            doc.add(buyerTable);

            // Footer
            doc.add(new Paragraph("_".repeat(80))
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginTop(20)
                    .setMarginBottom(10));
            Paragraph footer = new Paragraph("Thank you for using Mazadat! This is an official receipt.")
                    .setTextAlignment(TextAlignment.CENTER)
                    .setFontSize(10);
            doc.add(footer);

            // Close document - this will automatically close PdfDocument and Writer
            doc.close();

            return baos.toByteArray();
        } catch (Exception e) {
            throw new ApiException("Error generating PDF: " + e.getMessage());
        }
    }

    private Paragraph labelCell(String text, PdfFont font) {
        return new Paragraph(text)
                .setFont(font)
                .setBaseDirection(BaseDirection.LEFT_TO_RIGHT)
                .setTextAlignment(TextAlignment.LEFT);
    }

    private Paragraph valueCell(String text, PdfFont font) {
        String safe = text == null ? "" : text;
        boolean rtl = containsArabic(safe);

        return new Paragraph(safe)
                .setFont(font)
                .setBaseDirection(rtl ? BaseDirection.RIGHT_TO_LEFT : BaseDirection.LEFT_TO_RIGHT)
                .setTextAlignment(rtl ? TextAlignment.RIGHT : TextAlignment.LEFT);
    }

    private boolean containsArabic(String text) {
        if (text == null || text.isEmpty()) {
            return false;
        }
        return text.matches(".*[\\u0600-\\u06FF\\u0750-\\u077F\\u08A0-\\u08FF\\uFB50-\\uFDFF\\uFE70-\\uFEFF].*");
    }

    private PdfFont loadUnicodeFont() {
        try {
            // If you add a bundled font later, keep this first.
            ClassPathResource bundledFont = new ClassPathResource("static/fonts/NotoNaskhArabic-Regular.ttf");
            if (bundledFont.exists()) {
                return PdfFontFactory.createFont(
                        inputStreamToByteArray(bundledFont.getInputStream()),
                        PdfEncodings.IDENTITY_H,
                        PdfFontFactory.EmbeddingStrategy.PREFER_EMBEDDED
                );
            }
        } catch (Exception ignored) {
            // Fallbacks below
        }

        try {
            // Windows fallback for local development/runtime.
            return PdfFontFactory.createFont(
                    "C:/Windows/Fonts/arial.ttf",
                    PdfEncodings.IDENTITY_H,
                    PdfFontFactory.EmbeddingStrategy.PREFER_EMBEDDED
            );
        } catch (Exception ignored) {
            // Final fallback
        }

        try {
            return PdfFontFactory.createFont();
        } catch (Exception e) {
            throw new ApiException("Unable to load a PDF font: " + e.getMessage());
        }
    }

    private byte[] inputStreamToByteArray(InputStream is) throws Exception {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        int nRead;
        byte[] data = new byte[16384];
        while ((nRead = is.read(data, 0, data.length)) != -1) {
            buffer.write(data, 0, nRead);
        }
        return buffer.toByteArray();
    }
}

import { api } from './apiClient';

export const placeBid = (auctionId, amount) =>
    api.post('/bid/add', { auctionId, amount });

export const getBuyerBids = () =>
    api.get('/bid/buyer/my-bids');

export const getWonBids = () =>
    api.get('/bid/buyer/won-bids');

export const generateReceipt = async (auctionId) => {
    try {
        const blob = await api.post(`/receipt/generate/${auctionId}`, null, {
            responseType: 'blob',
        });

        if (!(blob instanceof Blob) || blob.size === 0) {
            throw new Error('Generated receipt is empty');
        }

        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', `receipt_${auctionId}.pdf`);
        document.body.appendChild(link);
        link.click();
        link.remove();
        window.URL.revokeObjectURL(url);

        return { success: true };
    } catch (error) {
        throw error;
    }
};

import { api } from './apiClient';

export const placeBid = (auctionId, amount) =>
    api.post('/bid/add', { auctionId, amount });

export const getBuyerBids = () =>
    api.get('/bid/buyer/my-bids');

export const getWonBids = () =>
    api.get('/bid/buyer/won-bids');

export const generateReceipt = async (auctionId) => {
    try {
        const blob = await api.post(`/receipt/generate/${auctionId}`, null, {
            responseType: 'blob',
        });

        if (!(blob instanceof Blob) || blob.size === 0) {
            throw new Error('Generated receipt is empty');
        }

        const signature = await blob.slice(0, 4).text();
        if (signature !== '%PDF') {
            throw new Error('Server returned an invalid receipt file');
        }

        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', `receipt_${auctionId}.pdf`);
        document.body.appendChild(link);
        link.click();
        link.remove();
        window.URL.revokeObjectURL(url);

        return { success: true };
    } catch (error) {
        throw error;
    }
};

'use client'

import * as React from 'react'
import * as SliderPrimitive from '@radix-ui/react-slider'

import { cn } from '@/lib/utils'

function Slider({
  className,
  defaultValue,
  value,
  min = 0,
  max = 100,
  ...props
}: React.ComponentProps<typeof SliderPrimitive.Root>) {
  const _values = React.useMemo(
    () =>
      Array.isArray(value)
        ? value
        : Array.isArray(defaultValue)
          ? defaultValue
          : [min, max],
    [value, defaultValue, min, max],
  )

  // Detect RTL from document
  const [isRTL, setIsRTL] = React.useState(false)

  React.useEffect(() => {
    const updateRTL = () => {
      if (typeof document !== 'undefined') {
        const htmlDir = document.documentElement.getAttribute('dir')
        setIsRTL(htmlDir === 'rtl')
      }
    }

    updateRTL()

    // Watch for direction changes (when language switches)
    const observer = new MutationObserver(updateRTL)
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ['dir'],
    })

    return () => observer.disconnect()
  }, [])

  return (
    <SliderPrimitive.Root
      data-slot="slider"
      defaultValue={defaultValue}
      value={value}
      min={min}
      max={max}
      className={cn(
        'relative flex w-full touch-none items-center select-none py-1 data-[disabled]:opacity-50 data-[orientation=vertical]:h-full data-[orientation=vertical]:min-h-44 data-[orientation=vertical]:w-auto data-[orientation=vertical]:flex-col',
        isRTL && '[direction:rtl]',
        className,
      )}
      {...props}
    >
      <SliderPrimitive.Track
        data-slot="slider-track"
        className={
          'relative grow overflow-hidden rounded-full bg-[#D9EEEB] data-[orientation=horizontal]:h-2.5 data-[orientation=horizontal]:w-full data-[orientation=vertical]:h-full data-[orientation=vertical]:w-2.5'
        }
      >
        <SliderPrimitive.Range
          data-slot="slider-range"
          className={
            'absolute bg-gradient-to-r from-[#2A9D8F] to-[#1A7A6E] data-[orientation=horizontal]:h-full data-[orientation=vertical]:w-full'
          }
        />
      </SliderPrimitive.Track>
      {Array.from({ length: _values.length }, (_, index) => (
        <SliderPrimitive.Thumb
          data-slot="slider-thumb"
          key={index}
          className="block size-5 shrink-0 rounded-full border-2 border-white bg-[#2A9D8F] shadow-[0_4px_14px_rgba(42,157,143,0.35)] transition-transform duration-150 hover:scale-110 focus-visible:scale-110 focus-visible:outline-none focus-visible:ring-4 focus-visible:ring-[#2A9D8F]/35 disabled:pointer-events-none disabled:opacity-50"
        />
      ))}
    </SliderPrimitive.Root>
  )
}

